VALUES ('rule-tt-rbac-02', 'TT-RBAC-02', 'CRUD is per role, per table, per field', 'rbac', 125, 'What each role may create/read/update/delete is data at the table and field grain; the enforced API consults it on every operation.', 'Roles / ERBTables.*CRUD / ERBFields', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-rbac-03', 'TT-RBAC-03', 'Row access follows per-role WHERE policies', 'rbac', 126, 'Each role-table pair carries a WHERE policy; a representative sees only their own citations while admin sees all, enforced on every vw_* read.', 'ERBTables / vw_citations (row-level security)', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-rbac-04', 'TT-RBAC-04', 'Lower-trust roles get redacted projections', 'rbac', 127, 'Fields denied to a role (e.g. PII for external-llm) are stripped from responses at projection time, not nulled afterward.', 'ERBFields (field CRUD) / role-specific views', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-nav-01', 'TT-NAV-01', 'Navigation is derived from PlatformNaviation rows', 'navigation', 128, 'The sidebar and route tree render from PlatformNaviation filtered by the current role''s RoleVisibility; there is no hand-maintained menu.', 'PlatformNaviation.RoleVisibility / ParentRouteKey', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-nav-02', 'TT-NAV-02', 'Route order and pinning are data', 'navigation', 129, 'NavLevel, SortOrder, and PinToTop on PlatformNaviation determine ordering and which screens float to the top.', 'PlatformNaviation.NavLevel / SortOrder / PinToTop', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-auth-01', 'TT-AUTH-01', 'Identity is resolved per request from the magic-link session', 'auth', 130, 'Each request resolves to an AppUsers row and role via the MagicLinkConfig flow; identity feeds every RBAC and scoping decision.', 'AppUsers / MagicLinkConfig', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-license-pkg-01', 'TT-LICENSE-PKG-01', 'Surfaces are gated by license/active flags', 'licensing', 131, 'Packages, features, tables, and routes carry IsLicensed/IsActive flags; unlicensed surfaces are revealed as upgrade prompts, not deleted.', 'ERBPackages.IsLicensed / ERBFeatures.IsLicensed / ERBTables.IsLicensed / PlatformNaviation.IsLicensed', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

