VALUES ('rule-tt-platform-01', 'TT-PLATFORM-01', 'The rulebook JSON is the single source of truth', 'platform', 132, 'All substrates (Postgres, Python, explain-dag, rulespeak) are mechanically derived from the rulebook by effortless build; edits go to the rulebook.', 'traffic-ticket-contest-rulebook.json', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

