VALUES ('rule-tt-platform-02', 'TT-PLATFORM-02', 'The platform describes itself', 'platform', 133, 'ERBTables/ERBFields/ERBFeatures/ERBPackages catalog every table, field, capability, and package so the app can render its own model.', 'ERBTables / ERBFields / ERBFeatures / ERBPackages', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('rule-tt-platform-03', 'TT-PLATFORM-03', 'Build is generate + load; drift is guarded', 'platform', 134, 'effortless build regenerates DDL/views/inserts and reloads the DB; a drift guard warns before a rebuild would clobber un-saved DB edits.', 'postgres-bootstrap/* / build pipeline', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

