INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('TT-DETERMINATION-01', 'TT-DETERMINATION-01', 'Determination is recorded', 'rules-engine', 136, 'A hearing determination (upheld / dismissed / reduced) must be recorded on the Citation before the citation-lifecycle may advance to adjudicated, and it writes a CaseEvents entry.', 'Citations.DeterminationResult', '2026-06-07T19:15:00Z', 'admin-example', '2026-06-07T19:15:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

INSERT INTO business_rules (business_rule_id, rule_code, title, category, sort_order, description, schema_location, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('TT-DETERMINATION-02', 'TT-DETERMINATION-02', 'Dismissal reverses consequences', 'rules-engine', 137, 'When a determination dismisses a Citation, any assessed license points are reversed and any paid amount is refunded, restoring the Driver to make-whole state.', 'Citations.AmountDue', '2026-06-07T19:15:00Z', 'admin-example', '2026-06-07T19:15:00Z', 'admin-example', NULL) ON CONFLICT (business_rule_id) DO NOTHING;

