VALUES ('term-jurisdiction', 'Jurisdiction', 'legal', 2, 'The regulatory authority (county or city) that issued a citation. Its row holds every deadline, fine, penalty, and point threshold that governs cases under it.', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (glossary_term_id) DO NOTHING;

