VALUES ('term-hearing', 'Hearing', 'legal', 3, 'A contest event: requested by the driver, scheduled by a manager, and concluded with an outcome (e.g. Dismissed) that drives liability.', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, category, sort_order, definition, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('term-rules-engine', 'Rules Engine', 'legal', 4, 'The pattern of expressing regulations as data on the Jurisdictions table, so changing a value re-derives every dependent citation with no code change.', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (glossary_term_id) DO NOTHING;

