INSERT INTO jurisdiction_source_documents (jurisdiction_source_document_id, title, jurisdiction, doc_type, relative_file_path, source_url, extracted_text, notes, jurisdiction_rules, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('doc-ca-vc-deadlines', 'California Vehicle Code — Arraignment & Bail Deadlines', 'j-ca-la', 'statute', 'git-ignored-examples/jurisdiction-rules/ca-vc-arraignment.pdf', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=VEH', 'A defendant cited for an infraction must appear or pay bail within the time set by the court, generally within 21 days of the notice to appear. Failure to appear may result in a civil assessment and referral for collection.', 'Source for CA-LA DaysToRespond = 21 and the default-judgment behavior.', NULL, '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (jurisdiction_source_document_id) DO NOTHING;

INSERT INTO jurisdiction_source_documents (jurisdiction_source_document_id, title, jurisdiction, doc_type, relative_file_path, source_url, extracted_text, notes, jurisdiction_rules, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('doc-ca-traffic-school', 'Los Angeles County Traffic School Eligibility Guidance', 'j-ca-la', 'guidance', 'git-ignored-examples/jurisdiction-rules/ca-la-traffic-school.pdf', 'https://www.courts.ca.gov/traffic.htm', 'Eligible drivers may attend traffic school once every 18 months to mask one point from a qualifying moving violation. Commercial license holders and certain violations are excluded.', 'Source for CA-LA TrafficSchoolPointCap = 1.', NULL, '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (jurisdiction_source_document_id) DO NOTHING;

INSERT INTO jurisdiction_source_documents (jurisdiction_source_document_id, title, jurisdiction, doc_type, relative_file_path, source_url, extracted_text, notes, jurisdiction_rules, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('doc-ny-vtl-points', 'New York Vehicle & Traffic Law — Point System', 'j-ny-nyc', 'statute', 'git-ignored-examples/jurisdiction-rules/ny-vtl-points.pdf', 'https://dmv.ny.gov/tickets/about-nys-driver-point-system', 'The NYS driver point system assigns points by violation. Accumulating 11 points within 18 months may result in license suspension; the DMV may also act on fewer points for serious offenses.', 'Source for NY-NYC PointSuspensionThreshold = 11 and PointWarningThreshold = 6.', NULL, '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (jurisdiction_source_document_id) DO NOTHING;

INSERT INTO jurisdiction_source_documents (jurisdiction_source_document_id, title, jurisdiction, doc_type, relative_file_path, source_url, extracted_text, notes, jurisdiction_rules, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('doc-tx-transportation-code', 'Texas Transportation Code — Speed & Signal Offenses', 'j-tx-aus', 'statute', 'git-ignored-examples/jurisdiction-rules/tx-transportation-code.pdf', 'https://statutes.capitol.texas.gov/Docs/TN/htm/TN.545.htm', 'An operator shall comply with posted speed limits and traffic-control signals. A defendant must respond to a citation within the period stated on the notice, commonly 14 days, or a warrant and additional fees may issue.', 'Source for TX-AUS DaysToRespond = 14 and signal/speed violation definitions.', NULL, '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (jurisdiction_source_document_id) DO NOTHING;

INSERT INTO jurisdiction_source_documents (jurisdiction_source_document_id, title, jurisdiction, doc_type, relative_file_path, source_url, extracted_text, notes, jurisdiction_rules, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('doc-tx-aus-appeal-2025-114', 'Travis County Appeal Board Decision 2025-114 (Radar Calibration)', 'j-tx-aus', 'appeal-board-decision', 'git-ignored-examples/jurisdiction-rules/tx-aus-appeal-2025-114.pdf', 'https://www.traviscountytx.gov/justice-of-the-peace', 'Where the issuing agency cannot produce radar/lidar calibration records upon timely request, the speed measurement is unreliable and the citation must be dismissed. Calibration logs must be retained and produced at hearing.', 'Directly supports the dismissal of citation TC-2026-0003 (Carlos Mendez) at hearing on 2026-04-15.', NULL, '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (jurisdiction_source_document_id) DO NOTHING;

