VALUES ('jr-ca-respond-21', NULL, 'CA-VC-§40519', '21-Day Response Window', 'An infraction defendant must appear or post bail within 21 days of the notice to appear; otherwise a civil assessment and collections referral may follow.', 'deadline', '2026-01-01', 'https://leginfo.legislature.ca.gov/faces/codes_displayText.xhtml?lawCode=VEH', 'In LA County you have 21 days from your ticket date to pay or ask for a hearing. Miss it and the court can decide against you and add a collection fee.', '2026-06-06T12:00:00Z', 'gpt-4o', 'doc-ca-vc-deadlines', 'j-ca-la', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', 'gpt-4o') ON CONFLICT (jurisdiction_rule_id) DO NOTHING;

INSERT INTO jurisdiction_rules (jurisdiction_rule_id, route, rule_number, title, description, category, effective_date, citation_url, ai_version, ai_version_updated_at, ai_version_model, source_document, jurisdiction, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('jr-ca-school-1pt', NULL, 'CA-LA-TS-1', 'Traffic School Masks One Point', 'An eligible driver may attend traffic school once per 18 months to mask one point from a qualifying moving violation.', 'license', '2026-01-01', 'https://www.courts.ca.gov/traffic.htm', 'In LA County you can take traffic school once every 18 months to hide one point from your record.', '2026-06-06T12:00:00Z', 'gpt-4o-mini', 'doc-ca-traffic-school', 'j-ca-la', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', 'gpt-4o-mini') ON CONFLICT (jurisdiction_rule_id) DO NOTHING;

INSERT INTO jurisdiction_rules (jurisdiction_rule_id, route, rule_number, title, description, category, effective_date, citation_url, ai_version, ai_version_updated_at, ai_version_model, source_document, jurisdiction, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('jr-ny-suspend-11', NULL, 'NY-VTL-§510', '11-Point Suspension Threshold', 'Accumulating 11 points within 18 months may result in license suspension; a warning is appropriate well before that.', 'license', '2026-01-01', 'https://dmv.ny.gov/tickets/about-nys-driver-point-system', 'In NYC, 11 points in 18 months can get your license suspended — we flag a warning at 6.', '2026-06-06T12:00:00Z', 'gpt-4o', 'doc-ny-vtl-points', 'j-ny-nyc', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', 'gpt-4o') ON CONFLICT (jurisdiction_rule_id) DO NOTHING;

INSERT INTO jurisdiction_rules (jurisdiction_rule_id, route, rule_number, title, description, category, effective_date, citation_url, ai_version, ai_version_updated_at, ai_version_model, source_document, jurisdiction, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('jr-tx-respond-14', NULL, 'TX-TC-§543', '14-Day Response Window', 'A defendant must respond to a citation within the period stated on the notice, commonly 14 days, or a warrant and additional fees may issue.', 'deadline', '2026-01-01', 'https://statutes.capitol.texas.gov/Docs/TN/htm/TN.545.htm', 'In Travis County you usually have 14 days to respond to a ticket before a warrant and extra fees can be added.', '2026-06-06T12:00:00Z', 'gpt-4o-mini', 'doc-tx-transportation-code', 'j-tx-aus', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', 'gpt-4o-mini') ON CONFLICT (jurisdiction_rule_id) DO NOTHING;

INSERT INTO jurisdiction_rules (jurisdiction_rule_id, route, rule_number, title, description, category, effective_date, citation_url, ai_version, ai_version_updated_at, ai_version_model, source_document, jurisdiction, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('jr-tx-radar-dismiss', NULL, 'TX-AUS-AB-2025-114', 'No Calibration Records → Dismissal', 'If the agency cannot produce radar/lidar calibration records on timely request, the speed reading is unreliable and the citation must be dismissed.', 'evidence', '2025-11-01', 'https://www.traviscountytx.gov/justice-of-the-peace', 'In Travis County, if the police can''t show their radar was calibrated, a speeding ticket can be thrown out — exactly what happened on TC-2026-0003.', '2026-06-06T12:00:00Z', 'gpt-4o', 'doc-tx-aus-appeal-2025-114', 'j-tx-aus', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', 'gpt-4o') ON CONFLICT (jurisdiction_rule_id) DO NOTHING;

