VALUES ('turn-0003-dismiss-basis', '2026-04-15T15:30:00Z', 'responding', 'rulebook', '/citations/tc-2026-0003', 'citations.detail', 'c-0003', 'manager-example', 'gpt-4o', 'gpt-4o-2024-08', 'On what basis can TC-2026-0003 be dismissed?', 'Under Travis County Appeal Board decision AB-2025-114, if the agency cannot produce radar/lidar calibration records on timely request, the speed measurement is unreliable and the citation must be dismissed. The hearing notes confirm calibration records were not produced, so dismissal is supported.', '{"system_prompt_kind": "rulebook", "finish_reason": "stop", "usage": {"input_tokens": 3100, "cached_input_tokens": 1900, "output_tokens": 220}}', 3100, 1900, 220, 'manager-example', '2026-04-15T15:30:00Z', 'manager-example', 'gpt-4o') ON CONFLICT (assistant_turn_id) DO NOTHING;

