VALUES ('turn-0004-penalty', '2026-03-02T09:00:00Z', 'responding', 'claim', '/citations/tc-2026-0004', 'citations.detail', 'c-0004', 'representative-example', 'gpt-4o-mini', 'gpt-4o-mini-2025-07', 'How much does Carlos owe now on TC-2026-0004?', 'TC-2026-0004 has a base fine of $275 (Travis County red-light). The pay-by date passed on 2026-03-01, so Travis County''s 30% late penalty applies: $275 × 1.30 = $357.50. If it stays unpaid past the 45-day collections window, it moves to Collections.', '{"system_prompt_kind": "claim", "finish_reason": "stop", "usage": {"input_tokens": 1700, "cached_input_tokens": 1100, "output_tokens": 160}}', 1700, 1100, 160, 'representative-example', '2026-03-02T09:00:00Z', 'representative-example', 'gpt-4o-mini') ON CONFLICT (assistant_turn_id) DO NOTHING;

