VALUES ('citations', 'Citations & Contests', 'Core package: citations, hearings, payments, license points.', 'active', TRUE, TRUE, 1, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (erb_package_id) DO NOTHING;

INSERT INTO erb_packages (erb_package_id, title, description, status, is_active, is_licensed, sort_order, is_key, source_text, source_files, erb_features, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core', 'Core Platform', 'Cross-cutting platform machinery shared by all packages: the rulebook-driven permission model, role-specific schemas, the enforced CRUD API, row-level security, the generic state-machine backbone, the work queue, and dev-ops/build tooling.', 'shipped', TRUE, TRUE, 2, TRUE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (erb_package_id) DO NOTHING;

INSERT INTO erb_packages (erb_package_id, title, description, status, is_active, is_licensed, sort_order, is_key, source_text, source_files, erb_features, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('platform-meta', 'Platform Meta & Knowledge Base', 'The self-describing meta layer you usually keep hidden: the feature catalog and statuses, the table/field schema catalog, the custom API-endpoint registry, ERB versions, customizations, the glossary, and the business-rule library. Turn this off and the entire "how the platform describes itself" surface disappears, leaving just the working app.', 'shipped', TRUE, TRUE, 3, TRUE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (erb_package_id) DO NOTHING;

INSERT INTO erb_packages (erb_package_id, title, description, status, is_active, is_licensed, sort_order, is_key, source_text, source_files, erb_features, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('access-control', 'Roles & User Management', 'The role/user administration surface: the Roles catalog and the AppUsers directory, plus the role/user admin pages and the permission model (role→table→field CRUD, per-role WHERE policies, role-specific schemas, derived RLS). Turn it OFF and an admin temporarily loses the management tools — a quick way to see the simpler app a non-admin sees. The underlying RLS keeps enforcing in Postgres regardless; this only hides the management UI.', 'shipped', TRUE, TRUE, 4, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (erb_package_id) DO NOTHING;

INSERT INTO erb_packages (erb_package_id, title, description, status, is_active, is_licensed, sort_order, is_key, source_text, source_files, erb_features, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('state-machines', 'State Machine Admin', 'The state-machine configuration surface: the StateMachines / MachineStates / StateTransitionRules / StateTransitions tables and the admin routes that view and edit them (machines, states, transition rules, transition log). Turn it off to hide the entire state-machine admin UI; the machines still drive entity lifecycles in Postgres.', 'shipped', TRUE, TRUE, 5, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (erb_package_id) DO NOTHING;

INSERT INTO erb_packages (erb_package_id, title, description, status, is_active, is_licensed, sort_order, is_key, source_text, source_files, erb_features, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('assistant', 'Assistant & Cost Analytics', 'The portal assistant (the chat-agent state machine) plus its cost/usage telemetry: the AI model catalog (AiModels), the versioned model price book (ModelPricingVersions), and per-turn AssistantTurns rows whose token costs roll up to accounts and records. Turn it off to hide the assistant analytics surface; the assistant route still functions.', 'shipped', TRUE, TRUE, 6, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT (erb_package_id) DO NOTHING;

