-- ----------------------------------------------------------------------------
-- ERBFeatures: Seed data for ERBFeatures
-- ----------------------------------------------------------------------------
INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('citation-intake', 'nav-citations-detail', 'citations', TRUE, 'Citation Intake', 'Record a new traffic citation — driver, violation type, issuing jurisdiction, issue date — and immediately derive its response deadline from the jurisdiction''s DaysToRespond rule.', 'intake', 'shipped', 1, FALSE, 'TT-INTAKE-01,TT-INTAKE-02,TT-DEADLINE-01', 'Records a new traffic citation as a row in the Citations table -- driver (FK to Drivers), violation type (FK to ViolationTypes), issuing jurisdiction (FK to Jurisdictions), and issue date -- and immediately derives the response deadline from the jurisdiction''s DaysToRespond rule via vw_citations. An admin or representative captures the citation off a paper ticket and the computed ResponseDeadline column appears the moment the row is saved, with no manual date math. This is the front door of the whole citation-lifecycle state machine.', 'README.md', '/assets/feature-images/citation-intake.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('driver-response', 'nav-citations-detail', 'citations', TRUE, 'Driver Response', 'Capture the driver''s choice — pay now or request a hearing — and advance the citation from Issued to Responded before the response window closes.', 'intake', 'shipped', 2, FALSE, 'TT-INTAKE-03,TT-CONTEST-01', 'Captures the driver''s choice -- pay now or request a hearing -- writing it onto the Citations row and advancing the citation from Issued to Responded in vw_citations before the response window closes. A representative records the decision on behalf of the cited driver, and the contest-track state machine branches on it. The response and its timestamp become CaseEvents rows so the audit trail explains every move.', 'README.md', '/assets/feature-images/driver-response.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('citation-statemachine', 'nav-citations-detail', 'citations', TRUE, 'Citation Lifecycle Tracker', 'Show the live Citation status (Issued → Responded → InContest → Adjudicated → Closed) re-derived from facts and child events — never a stored, drifting column.', 'state-machine', 'shipped', 3, FALSE, 'TT-CITATION-01,TT-CITATION-02', 'Shows the live Citation status (Issued -> Responded -> InContest -> Adjudicated -> Closed) re-derived on every read from facts and child CaseEvents rows in vw_citations -- never a stored, drifting column. A user opens a citation and sees a glowing status path that always reflects current reality. The same computed CitationStatus column drives the work queue and the dashboards.', 'README.md', '/assets/feature-images/citation-statemachine.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('contest-track', 'nav-citations-detail', 'citations', TRUE, 'Contest Tracker', 'Derive the contest track (NotContested | HearingRequested → Scheduled → Heard) from the latest hearing, driving liability downstream.', 'state-machine', 'shipped', 4, FALSE, 'TT-CONTEST-02,TT-CONTEST-03,TT-HEARING-01', 'Derives the contest track (NotContested | HearingRequested -> Scheduled -> Heard) from the latest Hearings row, surfacing it as a calculated column on vw_citations that drives liability downstream. A representative tracking a contested ticket sees exactly where the hearing process stands. The track feeds the determination logic that decides whether a fine is owed.', 'README.md', '/assets/feature-images/contest-track.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('payment-track', 'nav-payments', 'citations', TRUE, 'Payment & Penalty Tracker', 'Compute the payment track (Pending → Due → Late → Collections | Paid | NotOwed) including the jurisdiction-specific late penalty once the pay-by date passes.', 'state-machine', 'in-progress', 5, FALSE, 'TT-PAYMENT-01,TT-PAYMENT-02,TT-FEE-01', 'Computes the payment track (Pending -> Due -> Late -> Collections | Paid | NotOwed) on vw_citations, including the jurisdiction-specific late penalty once the pay-by date passes, by joining Citations, Payments, and the jurisdiction''s penalty rule. A representative or driver sees the live amount owed and its escalation status. The Late and Collections transitions are the ones the deadline-driven work queue watches most.', 'README.md', '/assets/feature-images/payment-track.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('license-points', 'nav-drivers', 'citations', TRUE, 'License Points Monitor', 'Roll up a driver''s active points and drive the license track (Valid → Warning → Suspended) against each jurisdiction''s warning and suspension thresholds.', 'license', 'in-progress', 6, FALSE, 'TT-LICENSE-01,TT-LICENSE-02', 'Rolls up a driver''s active points across their Citations and drives the license track (Valid -> Warning -> Suspended) against each jurisdiction''s warning and suspension thresholds, exposed on vw_drivers. A manager reviewing a driver sees the points gauge and the resulting license standing. The aggregation re-runs on every read so a dismissed citation instantly lowers the active-point total.', 'README.md', '/assets/feature-images/license-points.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('jurisdiction-rules', 'nav-jurisdictions', 'citations', TRUE, 'Jurisdiction Rules Engine', 'Edit a jurisdiction''s deadlines, fines, penalty percentages, and point thresholds as data — and watch every citation under it re-derive instantly, with no code change and no migration.', 'rules-engine', 'shipped', 7, FALSE, 'TT-RULES-01,TT-DEADLINE-01,TT-FEE-01', 'Lets an admin edit a jurisdiction''s deadlines, fines, penalty percentages, and point thresholds as data in the Jurisdictions and JurisdictionRules tables -- and every citation under it re-derives instantly through vw_citations with no code change and no migration. A manager turns a single dial and the whole region''s computed deadlines and penalties move. This is the rules-as-data thesis of the entire platform.', 'README.md', '/assets/feature-images/jurisdiction-rules.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('hearing-scheduling', 'nav-hearings', 'citations', TRUE, 'Hearing Scheduling', 'Request a hearing, let a manager schedule it, and record the outcome — driving the contest track and the citation''s liability.', 'hearings', 'shipped', 8, FALSE, 'TT-HEARING-01,TT-HEARING-02,TT-CONTEST-03', 'Requests a hearing, lets a manager schedule it, and records the outcome as a Hearings row, driving the contest track and the citation''s liability on vw_citations. A representative requests, a manager assigns a date, and the recorded outcome flows back to determine whether a fine survives. Each step writes a CaseEvents row so the timeline is complete.', 'README.md', '/assets/feature-images/hearing-scheduling.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('payment-checkout', 'nav-citations-pay', 'citations', TRUE, 'Online Payment', 'Pay a citation''s fine online in full, record the payment, and close the case — the path Aisha Khan took on citation TC-2026-0005.', 'payments', 'shipped', 9, FALSE, 'TT-PAYMENT-01,TT-PAYMENT-03', 'Pays a citation''s fine online in full, records a Payments row, and closes the case on vw_citations -- the path Aisha Khan took on citation TC-2026-0005. A representative or driver completes checkout and the payment track flips to Paid. The closing transition is logged to CaseEvents and removes the item from the work queue.', 'README.md', '/assets/feature-images/payment-checkout.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('work-queue', 'nav-work-queue', 'citations', TRUE, 'Work Queue', 'A single prioritized list of everything needing attention now — overdue responses, due payments, upcoming hearings — bucketed by urgency.', 'workqueue', 'shipped', 10, FALSE, 'TT-DEADLINE-01,TT-QUEUE-01', 'Surfaces a single prioritized list of everything needing attention now -- overdue responses, due payments, upcoming hearings -- as WorkQueueItems rows bucketed by urgency, computed from the deadline columns on vw_citations. A representative starts their day here and works top-down by urgency. Each queue item links back to the citation, driver, and the rule that put it there.', 'README.md', '/assets/feature-images/work-queue.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('audit-trail', 'nav-admin-audit-log', 'citations', TRUE, 'Audit Trail', 'Every status change, override, and edit on a citation is logged append-only — a full history that sits alongside, and explains, the computed current state.', 'audit', 'shipped', 11, FALSE, 'TT-AUDIT-01,TT-AUDIT-02', 'Logs every status change, override, and edit on a citation append-only into AuditLogEntries and CaseEvents, a full history that sits alongside -- and explains -- the computed current state in vw_citations. A manager investigating a dispute opens the trail and sees exactly who changed what and when. The append-only log never contradicts the derived state; it narrates how the state got there.', 'README.md', '/assets/feature-images/audit-trail.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('ai-assistant', 'nav-assistant', 'citations', TRUE, 'AI Case Assistant', 'Ask plain-language questions about a citation, the rules, or the portal and get an answer — with input/output token usage and per-model cost tracked for every turn.', 'assistant', 'in-progress', 12, FALSE, 'TT-ASSISTANT-01,TT-ASSISTANT-02', 'Answers plain-language questions about a citation, the rules, or the portal by writing AssistantTurns rows, with input/output token usage and per-model cost tracked for every turn against AiModels and ModelPricingVersions. A representative asks ''what''s my deadline on TC-2026-0002?'' and gets a grounded answer plus a logged cost. Every turn is auditable and billable down to the token.', 'README.md', '/assets/feature-images/ai-assistant.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('glossary', 'nav-library-glossary', 'citations', TRUE, 'Glossary', 'Plain-language definitions of every term in the domain — citation, jurisdiction, contest, collections, points — grouped by category.', 'library', 'shipped', 13, FALSE, 'TT-GLOSSARY-01', 'Presents plain-language definitions of every domain term -- citation, jurisdiction, contest, collections, points -- as GlossaryTerms rows grouped by GlossaryCategories. Any user clicks a term in the UI and reads what it means in this platform. The glossary is the canonical vocabulary that features and rules are written against.', 'README.md', '/assets/feature-images/glossary.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('business-rules-browser', 'nav-library-business-rules', 'citations', TRUE, 'Business Rules Browser', 'Browse the full set of business rules (R1..R38) grouped by category, each linked to exactly where in the schema it is enforced.', 'library', 'shipped', 14, FALSE, 'TT-PLATFORM-02,TT-GLOSSARY-01', 'Browse the full set of business rules (R1..R38) grouped by category, each linked to exactly where in the schema it is enforced.', 'README.md', '/assets/feature-images/business-rules-browser.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('jurisdiction-library', 'nav-library-jurisdiction-docs', 'citations', TRUE, 'Jurisdiction Document Library', 'Browse the source documents (appeal-board decisions, statutes) and AI-distilled rule summaries backing each jurisdiction''s behavior.', 'library', 'planned', 15, FALSE, 'TT-RULES-02,TT-GLOSSARY-01', 'Browses the source documents (appeal-board decisions, statutes) and AI-distilled rule summaries backing each jurisdiction, stored as JurisdictionSourceDocuments and ReferenceDocuments rows linked to Jurisdictions. A representative researching a contest reads the actual authority behind a deadline or penalty. It closes the loop between the rules-as-data engine and the legal text that justifies each row.', 'README.md', '/assets/feature-images/jurisdiction-library.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('multi-jurisdiction-dashboard', 'nav-dashboard', 'citations', TRUE, 'Multi-Jurisdiction Dashboard', 'A top-level dashboard comparing the three jurisdictions side by side — response windows, fines, penalties, point thresholds — so the rules engine is visible at a glance.', 'rules-engine', 'designed', 16, FALSE, 'TT-RULES-01,TT-QUEUE-01', 'Aggregates citation volume, contest rates, payment status, and average points by jurisdiction into a dashboard reading from vw_citations and vw_drivers across all Jurisdictions rows. A manager compares CA-LA, NY-NYC, and TX-AUS at a glance and spots where deadlines or penalties are biting. Every tile is a live aggregation, never a cached snapshot.', 'README.md', '/assets/feature-images/multi-jurisdiction-dashboard.png', '2026-06-06T12:00:00Z', 'admin-example', '2026-06-06T12:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-roles-vocabulary', 'nav-admin-roles', 'access-control', TRUE, 'Canonical roles table', 'Roles meta table — single queryable role vocabulary (Admin/Manager/Representative/External-LLM) with DefaultCRUD; AppUsers and the domain actor tables FK into it.', 'platform', 'designed', 30, FALSE, 'TT-RBAC-01', 'Defines the canonical four-role vocabulary (admin, manager, representative, external-llm) as Roles rows that every permission, navigation, and redaction decision references. An admin manages the role catalog from one screen and the rest of the platform inherits it. There is exactly one source of truth for who the actors are.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-role-permission-model', 'nav-admin-permissions', 'access-control', TRUE, 'Role→Table→Field CRUD permission model', 'Additive/subtractive CRUD permissions. Resolution per (role,table,field,op): effective = ERBFields.{Role}CRUD ?? ERBTables.{Role}CRUD ?? Roles.DefaultCRUD (field overrides table overrides role default; NULL inherits the parent). op_allowed = effective CONTAINS the C/R/U/D letter (no dashes; e.g. CRUD, RU, RD). Derived {Role}Can{Op} booleans are BLANK when the source is NULL so inherit is distinguishable from explicit deny. Seed posture: Admin/Manager DefaultCRUD=CRUD, Rep/External-LLM=R; table grants NULL; calculated/lookup/aggregation fields pinned to R, raw fields NULL.', 'platform', 'designed', 31, TRUE, 'TT-RBAC-01,TT-RBAC-02', 'Encodes the Role -> Table -> Field CRUD permission model as data so that what each role may create, read, update, or delete is a row, not a hardcoded guard. An admin edits a grid and the enforced CRUD API changes behavior immediately. This declarative matrix is the backbone of the platform''s RBAC.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-table-where-policies', 'nav-admin-permissions', 'access-control', TRUE, 'Per-role table WHERE policies', 'Each ERBTables row carries a {Role}WHERE clause that limits vertical (row) access per role — the source for the derived RLS plan.', 'platform', 'designed', 32, FALSE, 'TT-RBAC-02,TT-RBAC-03', 'Stores a per-role row-scoping WHERE policy per table so a representative sees only their own citations while an admin sees all, expressed as data the enforced API compiles into vw_* reads. An admin authors the policy once and every query for that role is filtered. Row-level security becomes configuration, not code.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-role-specific-schemas', 'nav-admin-tables', 'access-control', TRUE, 'Role-specific schemas / column-limited views', 'Generated vw_* views per role exposing only columns whose resolved {Role}CRUD contains R (resolved via core-role-permission-model). One column-limited view per (role,table).', 'platform', 'designed', 33, TRUE, 'TT-RBAC-02,TT-RBAC-04', 'Generates role-specific, column-limited projections of each table so external-llm receives a redacted schema while admin gets the full set, derived from the field-level CRUD grid. A developer sees exactly the columns a role is entitled to. The same rulebook yields a different, safe view per audience.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-enforced-crud-api', 'nav-admin-endpoints', 'core', TRUE, 'Enforced CRUD API', 'A full CRUD API that enforces the Role→Table→Field permissions and the WHERE policies at request time.', 'platform', 'designed', 34, TRUE, 'TT-RBAC-01,TT-RBAC-02,TT-RBAC-03', 'Provides the single enforced CRUD API that reads the Role -> Table -> Field permission rows and the WHERE policies before every operation, so no caller can bypass RBAC. Every app screen and every external client goes through it. It is the one door, and the door checks the rulebook.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-rls-plan', 'nav-admin-permissions', 'access-control', TRUE, 'Derived row-level security plan', 'Derived RLS: one CREATE POLICY per (role,table) built from ERBTables.{Role}WHERE (and APIEndpoints.WhereClause for custom endpoints). NULL WHERE = no row restriction. Source for basic row-level security.', 'platform', 'designed', 35, FALSE, 'TT-RBAC-03', 'Compiles the per-role WHERE policies into a derived row-level-security plan that the enforced API applies to every vw_* read, turning declarative scoping rows into actual filtered results. An admin reviews the plan to confirm a representative truly cannot see another rep''s citations. The plan is regenerated from the rulebook, never hand-maintained.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-api-endpoints', 'nav-admin-endpoints', 'platform-meta', TRUE, 'Custom API endpoints registry', 'APIEndpoints table cataloging non-CRUD endpoints (actions/RPC) in addition to the standard CRUD operations, each with its own role visibility.', 'platform', 'designed', 36, FALSE, 'TT-PLATFORM-01,TT-RBAC-01', 'Maintains a registry of every custom (non-CRUD) API endpoint as APIEndpoints rows -- method, path, subject table, role visibility, and which state machine it triggers. An admin browses the verb surface of the whole platform in one place. Loop 4 populates this registry with every traffic-ticket action.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-schema-catalog', 'nav-admin-tables', 'platform-meta', TRUE, 'Self-describing schema catalog', 'ERBTables/ERBFields are the self-describing catalog of every rulebook table and field. Build is ADDITIVE ONLY: on each run it ADDS newly-introduced tables/fields and UPDATEs derived columns (e.g. FieldCount) but NEVER overwrites or deletes existing rows, so hand-set permissions survive.', 'devops', 'designed', 37, FALSE, 'TT-PLATFORM-02', 'Exposes a self-describing schema catalog built from ERBTables and ERBFields rows so the platform can render its own data model without external documentation. A developer inspects any table''s fields, types, and descriptions in the UI. The catalog stays in sync because it is generated from the rulebook itself.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-state-machine-backbone', 'nav-admin-state-machines', 'state-machines', TRUE, 'Generic state-machine backbone', 'Four mechanic tables (StateMachines, MachineStates, StateTransitionRules, StateTransitions) plus one polymorphic transition log unify all lifecycle/audit handling.', 'platform', 'designed', 38, TRUE, 'TT-CITATION-01,TT-PLATFORM-01', 'Provides the generic state-machine backbone -- StateMachines, MachineStates, StateTransitionRules, StateTransitions, SubjectStateInstances -- that the four traffic-ticket tracks are expressed in as data. An admin defines states and guarded transitions as rows and the engine enforces them. Every lifecycle in the platform rides this one substrate.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-work-queue', 'nav-work-queue', 'core', TRUE, 'Unified work queue', 'WorkQueueItems surfaces non-terminal subjects across the platform''s lifecycle entities, ordered by urgency, via a polymorphic pointer.', 'platform', 'designed', 39, FALSE, 'TT-QUEUE-01,TT-DEADLINE-01', 'Implements the unified work queue as WorkQueueItems rows computed from deadline and status columns across vw_citations, vw_hearings, and vw_payments. Any role sees the prioritized list scoped to what they may act on. It is the single ''what needs me now'' surface for the whole platform.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-feature-status-tracking', 'nav-admin-features', 'platform-meta', TRUE, 'Feature status tracking', 'ERBFeatureStatuses meta table with IsActive to separate the official shared view from design-only (DESIGNED) features.', 'devops', 'designed', 40, FALSE, 'TT-PLATFORM-02', 'Tracks the build status of every capability via ERBFeatures.Status (FK to ERBFeatureStatuses), so the feature catalog shows designed/planned/in-progress/shipped at a glance. A product owner sees exactly what is live. This very spine row is part of that catalog.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-build-pipeline', 'nav-admin-build-pipeline', 'core', TRUE, 'Rulebook-first build pipeline', 'effortless build regenerates postgres SQL from the rulebook SSoT; init-db applies it; catalog tables are kept in sync additively.', 'devops', 'designed', 41, TRUE, 'TT-PLATFORM-01,TT-PLATFORM-03', 'Drives the rulebook-first build pipeline: editing the rulebook JSON and running effortless build regenerates Postgres, Python, explain-dag, and rulespeak with no hand-written substrate code. A developer changes a rule and rebuilds; every spoke updates. The pipeline is the mechanism that makes the SSoT actually single.', 'README.md,rulespeak/rulespeak.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-magic-link-auth', 'nav-admin-users', 'core', TRUE, 'Magic-link authentication', 'Passwordless email-code auth issuing JWTs the API verifies; feeds the role/RLS layer.', 'devops', 'designed', 42, TRUE, 'TT-AUTH-01,TT-RBAC-01', 'Authenticates users with passwordless email magic links configured in MagicLinkConfig, resolving each request to an AppUsers identity and role. A user signs in with a code and the platform knows who they are. Identity feeds every RBAC and row-scoping decision downstream.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-roles-catalog-admin', 'nav-admin-roles', 'access-control', TRUE, 'Roles catalog & per-role dashboard', 'The interactive Roles catalog plus a per-role dashboard: each role opens to a hub showing its user roster, its default CRUD posture, and its redacted-role flag, with inline user-add. This is the top of the RBAC cascade made editable.', 'permissions', 'shipped', 20, FALSE, 'TT-RBAC-01,TT-RBAC-02', 'Gives admins a roles catalog with a per-role dashboard summarizing each role''s table/field grants and visible navigation, reading Roles, the permission grid, and PlatformNaviation. An admin audits a role''s full reach from one screen. It turns the abstract RBAC matrix into a legible per-role story.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-app-users-directory', 'nav-admin-users', 'access-control', TRUE, 'App-Users directory & user management', 'A searchable directory of every AppUser, groupable by role, with create-user and a per-user detail page (profile + inherited-access view). This is the people side of access control, paired with the Roles catalog.', 'auth', 'shipped', 21, FALSE, 'TT-AUTH-01,TT-RBAC-01', 'Provides the App-Users directory backed by the AppUsers table for creating, editing, and assigning roles to users. An admin manages who can log in and what role they hold. Every identity the magic-link flow resolves lives here.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-admin-equivalent-access', 'nav-admin-permissions', 'access-control', TRUE, 'Admin-equivalent cross-world access', 'Roles flagged admin-equivalent may browse any role''s URL world (/admin, /reps, /llm); everyone else is bounced to their own home world. This is what lets an administrator move freely across the three role surfaces.', 'permissions', 'shipped', 22, FALSE, 'TT-RBAC-03,TT-RBAC-01', 'Grants admin (and admin-equivalent) roles cross-world access so they can read and act across every jurisdiction and every representative''s caseload, enforced via the WHERE policies. An admin troubleshoots any citation regardless of owner. The breadth is itself a configured policy, not a hardcoded superuser bypass.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-role-url-worlds', 'nav-admin-route-designer', 'access-control', TRUE, 'Role URL worlds (/admin · /reps · /llm)', 'Every role gets its own slug-prefixed URL world, so the same React app presents a different navigable surface per role. The home world, redirects, and sidebar all key off the active slug.', 'navigation', 'shipped', 23, FALSE, 'TT-RBAC-04,TT-NAV-01', 'Routes each role into its own URL world (/admin, /reps, /llm) so navigation, scoping, and chrome match the actor, driven by PlatformNaviation RoleVisibility. A representative lands in /reps and sees only their tools. The same rulebook produces a tailored app per role.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-role-impersonation', 'nav-admin-users', 'access-control', TRUE, 'Role impersonation (view-as-role)', 'An admin can browse the platform exactly as another (redacted) role sees it by entering the External-LLM world, which sends an X-Impersonate-Role header so the API returns that role''s filtered, redacted projection.', 'auth', 'shipped', 24, FALSE, 'TT-RBAC-04,TT-AUTH-01', 'Lets an admin view-as-role to see precisely what a representative or external-llm would see, applying that role''s permission and WHERE policies live. An admin verifies redaction and scoping by walking in the role''s shoes. It is a debugging superpower that never weakens the real policies.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-default-crud-editor', 'nav-admin-permissions', 'access-control', TRUE, 'Per-role default CRUD editor', 'The four-state Create/Read/Update/Delete control at the top of the cascade: each role''s default posture is set with an inherit / grant / deny tri-state, and every table and field falls back to it unless overridden.', 'permissions', 'shipped', 25, FALSE, 'TT-RBAC-02', 'Provides a per-role default CRUD editor that sets the baseline create/read/update/delete a role gets on a table before field-level overrides, stored as permission rows. An admin sets sane defaults once. Field grids then refine the exceptions.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-table-where-policy-editor', 'nav-admin-permissions', 'access-control', TRUE, 'Per-table CRUD + WHERE policy editor', 'On each table''s detail page an admin sets per-role CRUD overrides and a per-role WHERE clause that limits which rows that role can see. The WHERE policies are the source for the derived row-level-security plan.', 'permissions', 'shipped', 26, FALSE, 'TT-RBAC-03,TT-RBAC-02', 'A per-table CRUD + WHERE policy editor where an admin authors the row-scoping expression that filters a role''s reads of that table''s vw_*. An admin writes ''driver = current_user'' once for representatives. The enforced API compiles it on every query.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-field-crud-grid', 'nav-admin-permissions', 'access-control', TRUE, 'Per-field CRUD permission grid', 'A column-level grid where each field''s CRUD is granted or denied per role. Denied fields drop out of that role''s column-limited views, which is how role-specific schemas are produced.', 'permissions', 'shipped', 27, FALSE, 'TT-RBAC-02,TT-RBAC-04', 'A per-field CRUD permission grid that controls, column by column, what each role may read or write across every table, persisted as permission rows that the role-specific schemas derive from. An admin redacts a PII column for external-llm with one toggle. Granularity is data, not branching code.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-redaction-sweep', 'nav-admin-permissions', 'access-control', TRUE, 'Role-wide PII redaction sweep', 'Marking a role redacted runs a one-click sweep that bulk-denies every PII field carrying a *Redacted sibling, so the role transparently receives masked values instead of raw personal data across all tables.', 'permissions', 'shipped', 28, FALSE, 'TT-RBAC-04', 'Runs a role-wide PII redaction sweep that flags every sensitive field (driver address, license number) and ensures the field grid denies it to lower-trust roles. An admin confirms no PII leaks to external-llm in one pass. The sweep reads the field catalog and the grid together.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-redacted-projection', 'nav-admin-endpoints', 'access-control', TRUE, 'Redacted-response projection', 'When a redacted role (or an impersonation/LLM session) reads data, the server swaps in *_redacted columns so personal identifiers are masked in the response body itself — not merely hidden in the UI.', 'permissions', 'shipped', 29, FALSE, 'TT-RBAC-04', 'Produces the redacted-response projection the enforced API returns to a role, stripping denied columns from every vw_* result before it leaves the server. An external-llm receives a citation with PII columns absent, not nulled-after-the-fact. Redaction happens at projection time, deterministically.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-derived-rls', 'nav-admin-permissions', 'access-control', TRUE, 'Derived row-level security enforcement', 'The per-role WHERE policies and CRUD grants are compiled into role-scoped Postgres views and a search_path so that reads are filtered in the database itself, regardless of what the API or UI does.', 'permissions', 'shipped', 30, TRUE, 'TT-RBAC-03', 'Enforces derived row-level security by applying the compiled WHERE-policy plan to every read, so a representative''s query of vw_citations is silently scoped to their own rows. A rep simply cannot fetch another rep''s data. The enforcement is generated from the rulebook, audited, and uniform.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-live-identity', 'nav-admin-users', 'access-control', TRUE, 'Live per-request identity resolution', 'The JWT carries only an email; the role, redaction flag, and licensing visibility are looked up live from AppUsers on every request, so revoking or re-roling a user takes effect immediately without re-issuing tokens.', 'auth', 'shipped', 31, FALSE, 'TT-AUTH-01,TT-RBAC-01', 'Resolves live per-request identity from the magic-link session to an AppUsers row and role on every call, feeding RBAC and scoping with the actual current actor. The platform always knows who is asking right now. Stale or assumed identity is never used.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-route-designer', 'nav-admin-route-designer', 'core', TRUE, 'Route Designer (drag-drop nav tree)', 'A live, drag-and-drop editor for the entire platform navigation tree: reparent and reorder routes, edit their fields inline, create and delete routes, and set a per-route CRUD matrix — then SAVE promotes the tree back to the rulebook.', 'navigation', 'shipped', 20, TRUE, 'TT-NAV-01,TT-NAV-02', 'Offers a drag-and-drop Route Designer that edits the PlatformNaviation tree -- parent/child, level, role-visibility, pin-to-top -- as data that the live sidebar renders. An admin reorganizes the whole app''s navigation without touching code. The nav tree is rulebook rows end to end.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-live-sidebar', 'nav-admin-route-designer', 'core', TRUE, 'Live DB-driven sidebar', 'The sidebar is rendered entirely from the navigation table in the database: package-gated, role-filtered, with empty feature-status buckets auto-hidden and the active record''s context grafted in. Edit the routes and the menu changes.', 'navigation', 'shipped', 21, TRUE, 'TT-NAV-01,TT-RBAC-04', 'Renders a live DB-driven sidebar straight from PlatformNaviation rows filtered by the current role''s RoleVisibility. A user''s menu always matches the rulebook and their permissions. There is no hand-maintained menu file to drift.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-pin-to-top', 'nav-admin-route-designer', 'core', TRUE, 'Pin-to-top routes', 'A per-route PinToTop flag floats important destinations to the top of the sidebar regardless of their position in the tree, so high-traffic admin pages stay one click away.', 'navigation', 'shipped', 22, FALSE, 'TT-NAV-02', 'Supports pin-to-top routes via a PlatformNaviation.PinToTop flag so high-traffic screens (Work Queue, Citations) float above the long tail. An admin pins the screens reps use most. Ordering is data the sidebar honors.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-route-galleries', 'nav-admin-route-designer', 'core', TRUE, 'By-Role / By-Package route galleries', 'Two read-only regroupings of the same navigation set — one grouped by the roles that can reach each route, one by owning package — for auditing coverage at a glance; clicking jumps to that route in the designer tree.', 'navigation', 'shipped', 23, FALSE, 'TT-NAV-01,TT-PLATFORM-02', 'Generates By-Role and By-Package route galleries from PlatformNaviation so an admin can audit the app from either lens -- what each role sees, or what each package contributes. An admin reviews coverage gaps visually. Both galleries are projections of the same nav rows.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-route-access-gating', 'nav-admin-route-designer', 'core', TRUE, 'Per-route access gating', 'Visiting a URL a role isn''t permitted to read renders an Access-Denied surface instead of the page, enforced in the shell from the same permission data that filters the sidebar — so deep links can''t bypass the menu.', 'navigation', 'shipped', 24, FALSE, 'TT-NAV-01,TT-RBAC-04', 'Gates each route by RoleVisibility so navigating to a screen a role may not see returns a clean denial instead of a broken page, enforced from PlatformNaviation. A representative who edits the URL still cannot reach an admin screen. Access is checked against the rulebook on every navigation.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-nav-backed-pages', 'nav-admin-route-designer', 'core', TRUE, 'Generic nav-backed pages', 'Any navigation row that names a primary_view auto-renders a live, RLS-backed data grid plus a drill-down detail page — no bespoke component required. Most admin catalogs and logs are these generic pages.', 'navigation', 'shipped', 25, FALSE, 'TT-NAV-01,TT-NAV-02', 'Renders generic nav-backed pages: any PlatformNaviation row with a PrimaryTable/PrimaryView gets a working list-or-detail screen with no bespoke component, reading vw_* directly. An admin adds a screen by adding a nav row. The frontend is a renderer of rulebook data.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-dev-quick-connect', 'nav-admin-users', 'core', TRUE, 'Dev quick-connect login', 'A development-only login shortcut that lists @example.com demo users and issues a spoofed JWT in one click, so the team can hop between roles locally without the email-code round trip. Gated behind DEV_AUTH_ENABLED.', 'auth', 'shipped', 26, FALSE, 'TT-AUTH-01', 'Provides a dev quick-connect login that authenticates as any seeded AppUsers role for local testing without the full magic-link round trip. A developer hops between admin and representative in one click. It is a convenience that still resolves a real identity and real policies.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-unlicensed-reveal', 'nav-admin-packages', 'core', TRUE, 'Unlicensed-surface reveal', 'The vendor-only mechanism that lets Effortless staff see surfaces marked unlicensed, while accounts see them hidden. It is the internal key behind every per-feature, per-table, and per-package licensing toggle.', 'licensing', 'shipped', 27, FALSE, 'TT-LICENSE-PKG-01', 'Reveals unlicensed surfaces in a muted state -- features, tables, or routes whose ERBPackage is not licensed are shown as upgrade prompts rather than hidden -- driven by the IsLicensed flags. A buyer sees what the next tier unlocks. Licensing is presentation data, not a deleted feature.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-save-to-rulebook', 'nav-admin-build-pipeline', 'core', TRUE, 'SAVE: DB → rulebook → rebuild', 'The promotion action behind every admin editor: it exports the live admin-config tables out of Postgres back into the rulebook JSON, runs effortless build, then re-initializes the database — turning fast in-DB edits into the new source of truth.', 'devops', 'shipped', 28, TRUE, 'TT-PLATFORM-01,TT-PLATFORM-03', 'Implements SAVE: edits made in the admin UI write back to the rulebook JSON and trigger a rebuild, so the DB -> rulebook -> rebuild loop closes from inside the app. An admin changes a deadline and the rulebook plus all substrates update. The app edits its own source of truth.', 'README.md,rulespeak/rulespeak.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-drift-guard', 'nav-admin-build-pipeline', 'core', TRUE, 'Rulebook drift guard', 'Before a SAVE overwrites the rulebook, a guard checks whether the rulebook is newer than the last build manifest; if so it blocks with a 409 until the operator explicitly forces the write, preventing a stale admin session from clobbering newer changes.', 'devops', 'shipped', 29, FALSE, 'TT-PLATFORM-03', 'Adds a rulebook drift guard that detects when the live DB diverges from the rulebook JSON and surfaces it before a rebuild silently reverts edits. An admin is warned instead of losing work. The guard protects the SSoT from accidental clobber.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-config-export-scope', 'nav-admin-build-pipeline', 'core', TRUE, 'Config-export scope', 'The defined set of admin-config tables the exporter promotes on SAVE — navigation, packages, roles, tables, fields, endpoints, glossary, business rules, state machines, and branding — deliberately excluding operational data, which resets to seeds on rebuild.', 'devops', 'shipped', 30, FALSE, 'TT-PLATFORM-03,TT-LICENSE-PKG-01', 'Lets an admin choose the config-export scope -- which packages, tables, and routes ship in an exported rulebook -- so a tenant gets exactly the licensed subset. An admin exports a representative-only build. Scope is selected from the catalog, not edited by hand.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-permission-sync', 'nav-admin-permissions', 'core', TRUE, 'Non-destructive permission sync', 'A script that pushes the rulebook''s RBAC matrix into the live database without a full destructive init-db, so permission tweaks can be applied to a running instance while leaving operational data intact.', 'devops', 'shipped', 31, FALSE, 'TT-RBAC-02,TT-PLATFORM-03', 'Performs non-destructive permission sync: when new tables or fields appear, default grants are added without overwriting an admin''s existing customizations in the permission grid. An admin upgrades schema and keeps their RBAC edits. Sync is additive by design.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-endpoint-access-editor', 'nav-admin-endpoints', 'platform-meta', TRUE, 'Per-endpoint access editor', 'An editor for the custom API-endpoint registry where each endpoint, grouped by its subject table, gets a role allow-list and an optional WHERE clause — extending the same role/row scoping used on tables to bespoke endpoints.', 'permissions', 'shipped', 20, FALSE, 'TT-RBAC-01,TT-PLATFORM-01', 'A per-endpoint access editor that sets RoleVisibility on each APIEndpoints row, so a contest action is available to representatives but a refund only to managers. An admin tunes who can fire which verb. Endpoint security is a row, edited in the UI.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-package-toggle', 'nav-admin-packages', 'platform-meta', TRUE, 'Package enable/disable toggle', 'A switch per package that flips its active flag so the entire UI responds — the package''s routes, tables, and features disappear (or reappear) across the app at once, letting you demo the simpler product a non-admin sees.', 'licensing', 'in-progress', 21, FALSE, 'TT-LICENSE-PKG-01', 'Enables or disables whole ERBPackages via an IsActive toggle, lighting up or dimming every feature, table, and route under that package at once. An admin turns the assistant package off for a tenant. The toggle cascades through the catalog.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-package-licensing', 'nav-admin-packages', 'platform-meta', TRUE, 'Package licensing toggle', 'A per-package licensed flag that fences an entire package behind the vendor licensing model, so every route, table, and feature it owns is hidden from accounts while remaining visible to Effortless staff.', 'licensing', 'shipped', 22, FALSE, 'TT-LICENSE-PKG-01', 'Controls per-package licensing with an IsLicensed flag on ERBPackages that the unlicensed-reveal surface reads to gate paid capabilities. An admin sells the rules-engine package as a tier. Licensing state is data the whole UI respects.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-feature-licensing', 'nav-admin-features', 'platform-meta', TRUE, 'Per-feature licensing toggle', 'The LICENSED/UNLICENSED switch on each feature card and detail page, flipping a single feature''s own licensing flag independently of its package — used to fence off individual vendor-tooling features.', 'licensing', 'shipped', 23, FALSE, 'TT-LICENSE-PKG-01', 'Controls per-feature licensing via ERBFeatures.IsLicensed so individual capabilities can be gated even within a licensed package. An admin offers the AI assistant as an add-on. Granular licensing is a per-row flag.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-table-route-licensing', 'nav-admin-packages', 'platform-meta', TRUE, 'Per-table & per-route licensing toggles', 'Licensing flags at the individual table and route level, so a single catalog table or navigation destination can be hidden from accounts without disabling its whole package — the finest grain of the licensing model.', 'licensing', 'shipped', 24, FALSE, 'TT-LICENSE-PKG-01', 'Adds per-table and per-route licensing toggles (IsLicensed on ERBTables and PlatformNaviation) so a tier can expose a screen while withholding the underlying editable table. An admin shows read-only jurisdictions to a lower tier. Every surface has its own license switch.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-table-catalog', 'nav-admin-tables', 'platform-meta', TRUE, 'Self-describing table catalog', 'A browsable card grid of every rulebook table — package-gated and clickable through to each table''s permission/detail page. The schema describes itself, so the catalog is generated, never hand-listed.', 'data-model', 'shipped', 25, TRUE, 'TT-PLATFORM-02', 'Renders the self-describing table catalog from ERBTables rows -- name, package, field count, catalog flag, per-role CRUD -- so the platform documents its own schema. A developer browses every table and its governance from one screen. The catalog is generated, never written by hand.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-fields-catalog', 'nav-admin-fields', 'platform-meta', TRUE, 'Fields catalog', 'A live grid of every field across all tables — name, datatype, type (raw/calculated/lookup/relationship), and description — giving a single searchable index of the entire data model''s columns.', 'data-model', 'shipped', 26, TRUE, 'TT-PLATFORM-02', 'Renders the fields catalog from ERBFields rows -- table, field, type, datatype, description -- the column-level companion to the table catalog. A developer inspects exactly how each calculated or lookup field is defined. It is the field-level self-description of the rulebook.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-explainer-dag', 'nav-admin-explainer-dag', 'platform-meta', TRUE, 'Explainer DAG (calculated-field provenance)', 'A full-screen, interactive inference graph for any calculated field: click a value and trace its derivation back through lookups, intermediate calcs, and raw inputs — the platform showing exactly how a number was produced.', 'platform', 'shipped', 27, TRUE, 'TT-PLATFORM-02', 'Builds the Explainer DAG that visualizes calculated-field provenance -- click any computed cell and trace raw inputs -> lookups -> calcs -> aggregations -- generated from the rulebook''s formula graph. A user understands exactly how ResponseDeadline or ActivePoints was derived. It makes the inference graph witnessable.', 'README.md,rulespeak/rulespeak.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-feature-catalog-grid', 'nav-admin-features', 'platform-meta', TRUE, 'Feature catalog grid (filterable cards)', 'The Features page itself: a horizontal, filterable grid where every feature is a card with its own logo, searchable and narrowable by two orthogonal axes — lifecycle status and functional category. This very catalog is the feature.', 'platform', 'shipped', 28, TRUE, 'TT-PLATFORM-02', 'Presents the feature catalog as a filterable grid of cards from ERBFeatures, each with title, status, package, and cartoon logo. A product owner filters by status or package to see the platform''s surface. This is the home of the very rows Loop 1 enriches.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-feature-detail-editor', 'nav-admin-feature-detail', 'platform-meta', TRUE, 'Feature detail editor', 'The full-page dashboard for one feature — hero logo, stat strip, description, source narrative, rule refs, and metadata — with inline editing of title, description, status, category, sort order, rules, and sources.', 'platform', 'shipped', 29, FALSE, 'TT-PLATFORM-02,TT-PLATFORM-01', 'A feature detail editor for one ERBFeatures row -- title, description, SourceText, RuleRefs, status, route, image -- writing back to the rulebook. An admin documents a capability in place. The editor maintains the provenance spine this loop seeds.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-feature-vocab-editors', 'nav-admin-features', 'platform-meta', TRUE, 'Feature status & category editors', 'Drag-reorderable editors for the two feature vocabularies — lifecycle statuses and functional categories — where each bucket''s title, description, ordering, and flags are edited inline, including a per-status page that reorders the features within it.', 'platform', 'shipped', 30, FALSE, 'TT-PLATFORM-02', 'Provides editors for the feature vocabulary -- ERBFeatureStatuses and ERBFeatureCategories rows -- so the controlled lists behind the catalog are themselves editable data. An admin renames a status or adds a category. The taxonomy is rulebook-managed.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-feature-logo-system', 'nav-admin-features', 'platform-meta', TRUE, 'Cartoon feature-logo system', 'The convention that gives every feature its own cartoon logo by id (/feature-logos/<id>.png), with a graceful category-emoji fallback when an image is missing, plus a script that crops and resizes generated art to the standard tile.', 'platform', 'shipped', 31, FALSE, 'TT-PLATFORM-02', 'Runs the cartoon feature-logo system that attaches a generated ImageUrl to each ERBFeatures row for the catalog grid. An admin regenerates a logo and the card updates. Imagery is a per-feature data attribute.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-glossary-admin', 'nav-library-glossary', 'platform-meta', TRUE, 'Glossary admin', 'A drag-reorderable, inline-editable glossary of platform terms organized into categories, so the shared vocabulary lives in the rulebook and stays consistent across the app and its docs.', 'platform', 'shipped', 32, FALSE, 'TT-GLOSSARY-01', 'Gives admins glossary administration over GlossaryTerms and GlossaryCategories rows so the domain vocabulary stays current and complete. An admin adds ''collections'' the moment a rule references it. The glossary is edited as first-class data.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-business-rule-admin', 'nav-library-business-rules', 'platform-meta', TRUE, 'Business-rule library admin', 'A categorized, reorderable library of the platform''s business rules (the R-codes features reference), edited inline and promoted to the rulebook — the human-readable companion to the formulas the engine enforces.', 'platform', 'shipped', 33, FALSE, 'TT-PLATFORM-02', 'Provides business-rule library administration over BusinessRules and BusinessRuleCategories rows -- the numbered TT-* rules that features cite via RuleRefs. An admin authors a rule and links its SchemaLocation. Loop 2 fills this library so every RuleRef resolves.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-site-branding', 'nav-admin-branding', 'platform-meta', TRUE, 'Site-branding editor', 'A single-row editor for the platform''s identity — logo, colors, title, contact, and SEO — that applies the theme live as you type and serves public branding on the pre-auth login screen, then promotes to the rulebook on SAVE.', 'platform', 'shipped', 34, FALSE, 'TT-PLATFORM-02', 'A site-branding editor over the SiteBranding row -- company name, colors, logos, contact info, OG tags -- so the portal''s identity is data. An admin rebrands the whole app from one screen. Branding is configuration, not CSS edits.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-global-ui-settings', 'nav-admin-branding', 'platform-meta', TRUE, 'Global UI settings', 'Browser-level workspace preferences exposed on the System Config page — such as toggling calculated-field provenance glyphs and compact table density — stored locally so each operator can tune their own view.', 'platform', 'shipped', 35, FALSE, 'TT-PLATFORM-02', 'Exposes global UI settings (theme, density, defaults) backed by branding and meta rows that the frontend reads at boot. An admin tunes the look and feel for every user. Settings are stored, not compiled.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-state-machine-admin', 'nav-admin-state-machines', 'state-machines', TRUE, 'State-machine admin (visual + edit)', 'An admin surface for the generic state machines that drive entity lifecycles: a read-only flow diagram and transition log on one tab, and forms to edit machines, states, and transition rules on another.', 'platform', 'shipped', 20, FALSE, 'TT-CITATION-01,TT-PLATFORM-02', 'Offers visual state-machine administration -- view and edit StateMachines, MachineStates, and StateTransitionRules rows -- for the four traffic-ticket tracks. An admin adds a guarded transition as data. Loop 5 completes these machines.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('core-claim-lifecycle-sim', 'nav-admin-state-machines', 'state-machines', TRUE, 'Entity lifecycle simulator', 'An operational tool that walks a record forward and backward through its lifecycle state machine, so an operator can advance, replay, or correct a record''s stage and see the resulting transitions logged.', 'platform', 'shipped', 21, FALSE, 'TT-CITATION-01,TT-CITATION-02', 'Provides an entity lifecycle simulator that walks a sample citation through its state machine -- firing transitions, checking guards, logging StateTransitions -- to validate the model before real data. A developer dry-runs the citation lifecycle. It proves the machine is well-formed.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('as-portal-assistant', 'nav-assistant', 'assistant', TRUE, 'Portal assistant (context-aware chat)', 'A floating chat assistant that reads the current URL context (record, account, related entity) and runs a classify-then-answer flow grounded in that context, with an inspector that shows exactly what context it used.', 'platform', 'in-progress', 20, TRUE, 'TT-ASSISTANT-01,TT-ASSISTANT-02', 'The context-aware portal assistant chats about the current screen, citation, or rule, logging each exchange as AssistantTurns rows with model and cost. A user asks the assistant about whatever they are looking at. It grounds answers in the live vw_* data and the rulebook.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('as-cost-dashboard', 'nav-assistant-costs', 'assistant', TRUE, 'Cost-management dashboard', 'An analytics dashboard that rolls up assistant spend by model, account, record, and turn kind, backed by a versioned model price book — with drill-downs into per-account, per-record, and per-model detail.', 'dashboard', 'shipped', 21, FALSE, 'TT-ASSISTANT-02', 'A cost-management dashboard aggregating AssistantTurns by model and day against ModelPricingVersions to show spend and token volume. A manager watches assistant cost trend over time. Every figure is a live aggregation of logged turns.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('as-cost-telemetry', 'nav-assistant-costs', 'assistant', TRUE, 'Per-turn cost telemetry', 'Every assistant interaction is persisted as an AssistantTurns row with its token usage and computed cost, which then rolls up to the owning record and account — the data foundation the cost dashboard reads.', 'data-model', 'shipped', 22, FALSE, 'TT-ASSISTANT-02', 'Captures per-turn cost telemetry on each AssistantTurns row -- input tokens, output tokens, model, computed cost via ModelPricingVersions -- so spend is attributable to the turn. A developer audits a single expensive exchange. Cost is a stored, derived fact per turn.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

INSERT INTO erb_features (erb_feature_id, route, erb_package, is_licensed, title, description, category, status, sort_order, is_key, rule_refs, source_text, source_files, image_url, created_at, created_by, modified_at, modified_by, modified_by_model)
VALUES ('as-ocr-cost-estimator', 'nav-assistant-costs', 'assistant', TRUE, 'OCR cost estimator', 'An interactive planning tool with draggable dividers and sliders for modeling OCR routing and token allocation, so the cost of extracting a document set can be estimated before the work is run.', 'dashboard', 'shipped', 23, FALSE, 'TT-ASSISTANT-02', 'An OCR cost estimator that projects the token and dollar cost of processing a batch of citation images before running it, using AiModels and ModelPricingVersions rates. A manager budgets an intake batch up front. The estimate uses the same pricing rows that bill real turns.', 'README.md,EXPANSION-PLAN.md', '', '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_feature_id) DO NOTHING;

