VALUES ('PlatformNaviation.Depth', 'PlatformNaviation', 'Depth', 'calculated', 'integer', 'Calculated — nesting depth in the menu tree. 0 = top-level (no parent); otherwise the number of dot-segments in the dotted RouteKey above the root (e.g. ''library.rules.detail'' = 2). Drives N-deep indentation.', NULL, NULL, NULL, NULL, '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_field_id) DO NOTHING;

