VALUES ('PlatformNaviation.FullPath', 'PlatformNaviation', 'FullPath', 'calculated', 'string', 'Calculated — canonical role-agnostic URL path (equals Route). The SPA renders this under each permitted role as /:role + FullPath and resolves it only when that role''s *CanRead is true; the role is an implicit prefix, never stored on the row.', NULL, NULL, NULL, NULL, '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_field_id) DO NOTHING;

