VALUES ('PlatformNaviation.HandlerBaseName', 'PlatformNaviation', 'HandlerBaseName', 'calculated', 'string', 'Calculated — space-delimited form of the dotted RouteKey (dots and hyphens become spaces), e.g. ''library rules detail''. The client PascalCases this and prefixes the viewer role to derive the handler component deterministically: {Role} + PascalCase(HandlerBaseName) -> e.g. AdminLibraryRulesDetail, RepresentativeLibraryRulesDetail. No per-role handler is stored; edge cases get their own single-role route row instead.', NULL, NULL, NULL, NULL, '2026-06-07T00:00:00Z', 'admin-example', '2026-06-07T00:00:00Z', 'admin-example', NULL) ON CONFLICT (erb_field_id) DO NOTHING;

