VALUES ('tc-rule-R1', 'Rule enforced: R1 — Citation requires driver, violation and jurisdiction', 'A citation must reference exactly one driver, one violation type, and one issuing jurisdiction.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'R1', 'high', TRUE, 138, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

