VALUES ('tc-rule-R2', 'Rule enforced: R2 — Response due date is derived from the jurisdiction', 'ResponseDueDate = IssuedOn + the issuing jurisdiction''s DaysToRespond. Changing the jurisdiction''s rule re-derives every citation under it.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'R2', 'high', TRUE, 139, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

