VALUES ('tc-rule-R3', 'Rule enforced: R3 — A response is pay or contest', 'Responding means either paying the fine or requesting a hearing; either sets RespondedOn and advances the citation to Responded.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'R3', 'high', TRUE, 140, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

