VALUES ('tc-rule-TT-PAYMENT-01', 'Rule enforced: TT-PAYMENT-01 — Payment track derives from payments and pay-by date', 'PaymentStatus (Pending -> Due -> Late -> Collections | Paid | NotOwed) is computed from Payments rows and the jurisdiction pay-by date.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'TT-PAYMENT-01', 'high', TRUE, 167, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

