VALUES ('tc-rule-TT-PAYMENT-02', 'Rule enforced: TT-PAYMENT-02 — Late penalty applies after the pay-by date', 'Once the pay-by date passes with no full payment, the jurisdiction''s LatePenaltyPercent is added to AmountOwed.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'TT-PAYMENT-02', 'high', TRUE, 168, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-PAYMENT-03', 'Rule enforced: TT-PAYMENT-03 — Paid in full closes the case', 'When recorded Payments equal AmountOwed, PaymentStatus becomes Paid and the citation advances toward Closed.', 'rules', 'rules', 'sql', NULL, NULL, 'Payments', NULL, 'TT-PAYMENT-03', 'high', TRUE, 169, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-FEE-01', 'Rule enforced: TT-FEE-01 — Base fine comes from the violation and jurisdiction', 'The base fine is the ViolationType base amount adjusted by the jurisdiction''s fee schedule; it is data, not a constant.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'TT-FEE-01', 'high', TRUE, 170, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-LICENSE-01', 'Rule enforced: TT-LICENSE-01 — Active points roll up across a driver''s citations', 'A driver''s ActivePoints is the sum of points from non-dismissed, non-expired citations under each jurisdiction''s point window.', 'rules', 'rules', 'sql', NULL, NULL, 'Drivers', NULL, 'TT-LICENSE-01', 'high', TRUE, 171, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-LICENSE-02', 'Rule enforced: TT-LICENSE-02 — License track follows jurisdiction thresholds', 'LicenseStatus (Valid -> Warning -> Suspended) is derived by comparing ActivePoints against the jurisdiction''s warning and suspension thresholds.', 'rules', 'rules', 'sql', NULL, NULL, 'Drivers', NULL, 'TT-LICENSE-02', 'high', TRUE, 172, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-QUEUE-01', 'Rule enforced: TT-QUEUE-01 — Work queue is computed from deadlines and status', 'WorkQueueItems are derived from overdue responses, due/late payments, and upcoming hearings, bucketed by urgency; nothing is hand-enqueued.', 'rules', 'rules', 'sql', NULL, NULL, 'WorkQueueItems <- Citations / Hearings / Payments', NULL, 'TT-QUEUE-01', 'high', TRUE, 173, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-AUDIT-01', 'Rule enforced: TT-AUDIT-01 — Every state-affecting change is logged', 'Each status change, override, payment, and edit writes an append-only AuditLogEntries (and where lifecycle-relevant, a CaseEvents) row.', 'rules', 'rules', 'sql', NULL, NULL, 'AuditLogEntries / CaseEvents', NULL, 'TT-AUDIT-01', 'high', TRUE, 174, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-AUDIT-02', 'Rule enforced: TT-AUDIT-02 — The log never contradicts the derived state', 'The append-only history explains how current computed state was reached; it is additive narration, never an alternate source of truth.', 'rules', 'rules', 'sql', NULL, NULL, 'AuditLogEntries / Citations', NULL, 'TT-AUDIT-02', 'high', TRUE, 175, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-ASSISTANT-01', 'Rule enforced: TT-ASSISTANT-01 — Assistant answers are grounded in live data', 'The assistant answers about a citation/rule/portal from live vw_* reads and the rulebook, recording each exchange as an AssistantTurns row.', 'rules', 'rules', 'sql', NULL, NULL, 'AssistantTurns / vw_citations', NULL, 'TT-ASSISTANT-01', 'high', TRUE, 176, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-ASSISTANT-02', 'Rule enforced: TT-ASSISTANT-02 — Every turn is cost-accounted', 'Each AssistantTurns row records input/output tokens and a computed cost via ModelPricingVersions for the turn''s AiModel.', 'rules', 'rules', 'sql', NULL, NULL, 'AssistantTurns', NULL, 'TT-ASSISTANT-02', 'high', TRUE, 177, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-RULES-01', 'Rule enforced: TT-RULES-01 — Jurisdiction knobs are editable data', 'Deadlines, fines, penalty percentages, and point thresholds live in Jurisdictions/JurisdictionRules and every dependent value re-derives on edit.', 'rules', 'rules', 'sql', NULL, NULL, 'Jurisdictions / JurisdictionRules', NULL, 'TT-RULES-01', 'high', TRUE, 178, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-RULES-02', 'Rule enforced: TT-RULES-02 — Each jurisdiction rule cites its source', 'A JurisdictionRules row links to the JurisdictionSourceDocuments / ReferenceDocuments authority that justifies it.', 'rules', 'rules', 'sql', NULL, NULL, 'JurisdictionRules -> JurisdictionSourceDocuments / ReferenceDocuments', NULL, 'TT-RULES-02', 'high', TRUE, 179, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

