VALUES ('tc-rule-TT-RBAC-01', 'Rule enforced: TT-RBAC-01 — Four canonical roles govern access', 'Exactly four roles exist (admin, manager, representative, external-llm) and every permission decision references one of them.', 'rules', 'rules', 'sql', NULL, NULL, 'Roles', NULL, 'TT-RBAC-01', 'high', TRUE, 180, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-RBAC-02', 'Rule enforced: TT-RBAC-02 — CRUD is per role, per table, per field', 'What each role may create/read/update/delete is data at the table and field grain; the enforced API consults it on every operation.', 'rules', 'rules', 'sql', NULL, NULL, 'Roles / ERBTables', NULL, 'TT-RBAC-02', 'high', TRUE, 181, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

INSERT INTO test_case (test_case_id, title, description, test_category, test_surface, test_technology, target_feature, target_endpoint, target_table, target_transition, business_rule_refs, severity, is_enabled, order_index, created_at, created_by, modified_at, modified_by)
VALUES ('tc-rule-TT-RBAC-03', 'Rule enforced: TT-RBAC-03 — Row access follows per-role WHERE policies', 'Each role-table pair carries a WHERE policy; a representative sees only their own citations while admin sees all, enforced on every vw_* read.', 'rules', 'rules', 'sql', NULL, NULL, 'ERBTables / vw_citations (row-level security)', NULL, 'TT-RBAC-03', 'high', TRUE, 182, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

