VALUES ('tc-rule-TT-RBAC-04', 'Rule enforced: TT-RBAC-04 — Lower-trust roles get redacted projections', 'Fields denied to a role (e.g. PII for external-llm) are stripped from responses at projection time, not nulled afterward.', 'rules', 'rules', 'sql', NULL, NULL, 'ERBFields (field CRUD) / role-specific views', NULL, 'TT-RBAC-04', 'high', TRUE, 183, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

