VALUES ('tc-rule-TT-NAV-01', 'Rule enforced: TT-NAV-01 — Navigation is derived from PlatformNaviation rows', 'The sidebar and route tree render from PlatformNaviation filtered by the current role''s RoleVisibility; there is no hand-maintained menu.', 'rules', 'rules', 'sql', NULL, NULL, 'PlatformNaviation', NULL, 'TT-NAV-01', 'high', TRUE, 184, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

