VALUES ('tc-rule-TT-NAV-02', 'Rule enforced: TT-NAV-02 — Route order and pinning are data', 'NavLevel, SortOrder, and PinToTop on PlatformNaviation determine ordering and which screens float to the top.', 'rules', 'rules', 'sql', NULL, NULL, 'PlatformNaviation', NULL, 'TT-NAV-02', 'high', TRUE, 185, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

