VALUES ('tc-rule-TT-AUTH-01', 'Rule enforced: TT-AUTH-01 — Identity is resolved per request from the magic-link session', 'Each request resolves to an AppUsers row and role via the MagicLinkConfig flow; identity feeds every RBAC and scoping decision.', 'rules', 'rules', 'sql', NULL, NULL, 'AppUsers / MagicLinkConfig', NULL, 'TT-AUTH-01', 'high', TRUE, 186, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

