VALUES ('tc-rule-TT-LICENSE-PKG-01', 'Rule enforced: TT-LICENSE-PKG-01 — Surfaces are gated by license/active flags', 'Packages, features, tables, and routes carry IsLicensed/IsActive flags; unlicensed surfaces are revealed as upgrade prompts, not deleted.', 'rules', 'rules', 'sql', NULL, NULL, 'ERBPackages', NULL, 'TT-LICENSE-PKG-01', 'high', TRUE, 187, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

