VALUES ('tc-rule-TT-PLATFORM-01', 'Rule enforced: TT-PLATFORM-01 — The rulebook JSON is the single source of truth', 'All substrates (Postgres, Python, explain-dag, rulespeak) are mechanically derived from the rulebook by effortless build; edits go to the rulebook.', 'rules', 'rules', 'sql', NULL, NULL, 'traffic-ticket-contest-rulebook', NULL, 'TT-PLATFORM-01', 'high', TRUE, 188, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

