VALUES ('tc-rule-TT-PLATFORM-02', 'Rule enforced: TT-PLATFORM-02 — The platform describes itself', 'ERBTables/ERBFields/ERBFeatures/ERBPackages catalog every table, field, capability, and package so the app can render its own model.', 'rules', 'rules', 'sql', NULL, NULL, 'ERBTables / ERBFields / ERBFeatures / ERBPackages', NULL, 'TT-PLATFORM-02', 'high', TRUE, 189, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

