VALUES ('tc-rule-TT-PLATFORM-03', 'Rule enforced: TT-PLATFORM-03 — Build is generate + load; drift is guarded', 'effortless build regenerates DDL/views/inserts and reloads the DB; a drift guard warns before a rebuild would clobber un-saved DB edits.', 'rules', 'rules', 'sql', NULL, NULL, 'postgres-bootstrap/* / build pipeline', NULL, 'TT-PLATFORM-03', 'high', TRUE, 190, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

