VALUES ('tc-rule-TT-GLOSSARY-01', 'Rule enforced: TT-GLOSSARY-01 — Domain terms are defined as data', 'Every domain term used in a feature or rule is defined in GlossaryTerms under a GlossaryCategories group.', 'rules', 'rules', 'sql', NULL, NULL, 'GlossaryTerms / GlossaryCategories', NULL, 'TT-GLOSSARY-01', 'high', TRUE, 191, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

