VALUES ('tc-rule-TT-DETERMINATION-01', 'Rule enforced: TT-DETERMINATION-01 — Determination is recorded', 'A hearing determination (upheld / dismissed / reduced) must be recorded on the Citation before the citation-lifecycle may advance to adjudicated, and it writes a CaseEvents entry.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'TT-DETERMINATION-01', 'high', TRUE, 192, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

