VALUES ('tc-rule-TT-DETERMINATION-02', 'Rule enforced: TT-DETERMINATION-02 — Dismissal reverses consequences', 'When a determination dismisses a Citation, any assessed license points are reversed and any paid amount is refunded, restoring the Driver to make-whole state.', 'rules', 'rules', 'sql', NULL, NULL, 'Citations', NULL, 'TT-DETERMINATION-02', 'high', TRUE, 193, '2026-06-07T19:30:00Z', 'admin-example', '2026-06-07T19:30:00Z', 'admin-example') ON CONFLICT (test_case_id) DO NOTHING;

